(function($) {
'use strict';
var VH360CreatePost = {
EXCERPT_WARNING_THRESHOLD: 450,
EXCERPT_MAX_LENGTH: 500,
init: function() {
this.initCharacterCounter();
this.bindEvents();
},
bindEvents: function() {
var self = this;
$(document).on('click', '#vh360-post-upload-trigger', function(e) {
e.preventDefault();
e.stopPropagation();
document.getElementById('vh360_post_featured_image').click();
});
$(document).on('change', '#vh360_post_featured_image', function(e) {
self.handleImageSelect(e);
});
$(document).on('click', '#vh360-post-remove-image', function(e) {
e.preventDefault();
self.removeImage();
});
$(document).on('click', '#vh360-edit-upload-trigger', function(e) {
e.preventDefault();
e.stopPropagation();
document.getElementById('vh360-edit-featured-image').click();
});
$(document).on('change', '#vh360-edit-featured-image', function(e) {
self.handleEditImageSelect(e);
});
$(document).on('click', '#vh360-edit-remove-image', function(e) {
e.preventDefault();
self.removeEditImage();
});
var $form = $('.vh360-post-create-form');
if ($form.length) {
self.isSubmitting = false;
self.initialFormState = $form.serialize();
self.debounceTimer = null;
$form.on('change input', 'input, textarea, select', function(e) {
clearTimeout(self.debounceTimer);
self.debounceTimer = setTimeout(function() {
var $createPostTab = $('#create-post');
if ($createPostTab.length && $createPostTab.hasClass('active')) {
var currentState = $form.serialize();
self.formModified = (currentState !== self.initialFormState);
}
}, 300);
});
$form.on('submit', function() {
clearTimeout(self.debounceTimer);
self.isSubmitting = true;
self.formModified = false;
});
$(document).on('click', '.vh360-dashboard-tab', function() {
var clickedTab = $(this).data('tab');
if (clickedTab !== 'create-post') {
clearTimeout(self.debounceTimer);
self.formModified = false;
}
});
}
$(document).on('click', '.vh360-post-card a[href][target="_blank"]', function() {
clearTimeout(self.debounceTimer);
self.formModified = false;
});
$(window).on('beforeunload', function(e) {
if (self.formModified && !self.isSubmitting) {
var $createPostTab = $('#create-post');
if ($createPostTab.length && $createPostTab.hasClass('active')) {
var title = $('#vh360_post_title').val().trim();
var content = $('#vh360_post_content').val().trim();
if (title || content) {
var message = 'You have unsaved changes. Are you sure you want to leave?';
e.returnValue = message;
return message;
}
}
}
});
$(document).on('submit', '.vh360-post-create-form', function(e) {
return self.validateForm($(this));
});
$(document).on('click', '.vh360-post-edit', function(e) {
e.preventDefault();
e.stopPropagation();
var postId = $(this).data('post-id');
self.openEditModal(postId);
});
$(document).on('click', '.vh360-post-delete', function(e) {
e.preventDefault();
e.stopPropagation();
var postId = $(this).data('post-id');
self.confirmDelete(postId);
});
$(document).on('click', '#vh360-post-edit-modal .vh360-modal-close, #vh360-post-edit-modal .vh360-modal-cancel, #vh360-post-delete-modal .vh360-modal-close, #vh360-post-delete-modal .vh360-modal-cancel', function(e) {
e.preventDefault();
e.stopPropagation();
self.closeModals();
});
$(document).on('click', '#vh360-post-edit-modal, #vh360-post-delete-modal', function(e) {
if (e.target === this) {
self.closeModals();
}
});
$(document).on('submit', '#vh360-post-edit-form', function(e) {
e.preventDefault();
self.updatePost();
});
$(document).on('click', '#vh360-post-confirm-delete', function(e) {
e.preventDefault();
self.deletePost();
});
$(document).on('input', '#vh360-edit-post-excerpt', function() {
var count = $(this).val().length;
$('#vh360-edit-char-count').text(count);
});
},
initCharacterCounter: function() {
var self = this;
var $excerpt = $('#vh360_post_excerpt');
var $counter = $('.vh360-char-count');
if ($excerpt.length && $counter.length) {
var currentLength = $excerpt.val().length;
$counter.text(currentLength);
if (currentLength > self.EXCERPT_WARNING_THRESHOLD) {
$counter.parent().addClass('vh360-char-warning');
} else {
$counter.parent().removeClass('vh360-char-warning');
}
$excerpt.on('input', function() {
var count = $(this).val().length;
$counter.text(count);
if (count > self.EXCERPT_WARNING_THRESHOLD) {
$counter.parent().addClass('vh360-char-warning');
} else {
$counter.parent().removeClass('vh360-char-warning');
}
});
}
},
handleImageSelect: function(e) {
var file = e.target.files[0];
if (!file) {
return;
}
this.clearError();
var validTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
if (validTypes.indexOf(file.type) === -1) {
this.showError('Please select a valid image file (JPG, PNG, GIF, or WebP).');
this.removeImage();
return;
}
var maxSize = 5 * 1024 * 1024;
if (file.size > maxSize) {
this.showError('Image file size must be less than 5MB.');
this.removeImage();
return;
}
var reader = new FileReader();
reader.onload = function(event) {
var $preview = $('#vh360-post-image-preview');
var $previewImg = $('#vh360-post-preview-img');
$previewImg.attr('src', event.target.result);
$preview.fadeIn(200);
};
reader.readAsDataURL(file);
},
validateForm: function($form) {
var self = this;
var isValid = true;
var errors = [];
this.clearError();
var title = $('#vh360_post_title').val().trim();
if (!title) {
errors.push('Post title is required.');
isValid = false;
}
var excerpt = $('#vh360_post_excerpt').val();
if (excerpt.length > self.EXCERPT_MAX_LENGTH) {
errors.push('Excerpt must be ' + self.EXCERPT_MAX_LENGTH + ' characters or less.');
isValid = false;
}
if (!isValid) {
var errorMessage = errors.join(' ');
this.showError(errorMessage);
}
return isValid;
},
showError: function(message) {
this.clearError();
var errorHtml = '<div class="vh360-form-error" role="alert">' +
'<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">' +
'<circle cx="12" cy="12" r="10"></circle>' +
'<line x1="12" y1="8" x2="12" y2="12"></line>' +
'<line x1="12" y1="16" x2="12.01" y2="16"></line>' +
'</svg>' +
'<span>' + message + '</span>' +
'</div>';
$('.vh360-post-create-form').before(errorHtml);
$('html, body').animate({
scrollTop: $('.vh360-form-error').offset().top - 100
}, 300);
},
clearError: function() {
$('.vh360-form-error').remove();
},
removeImage: function() {
$('#vh360_post_featured_image').val('');
$('#vh360-post-preview-img').attr('src', '');
$('#vh360-post-image-preview').fadeOut(200);
},
handleEditImageSelect: function(e) {
var file = e.target.files[0];
if (!file) {
return;
}
var validTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
if (validTypes.indexOf(file.type) === -1) {
this.showNotification('Please select a valid image file (JPG, PNG, GIF, or WebP).', 'error');
this.removeEditImage();
return;
}
var maxSize = 5 * 1024 * 1024;
if (file.size > maxSize) {
this.showNotification('Image file size must be less than 5MB.', 'error');
this.removeEditImage();
return;
}
var reader = new FileReader();
reader.onload = function(event) {
var $preview = $('#vh360-edit-image-preview');
var $previewImg = $('#vh360-edit-preview-img');
$previewImg.attr('src', event.target.result);
$preview.fadeIn(200);
};
reader.readAsDataURL(file);
$('#vh360-edit-featured-image-id').val('-1');
},
removeEditImage: function() {
$('#vh360-edit-featured-image').val('');
$('#vh360-edit-preview-img').attr('src', '');
$('#vh360-edit-image-preview').fadeOut(200);
$('#vh360-edit-featured-image-id').val('0');
},
openEditModal: function(postId) {
var self = this;
self.currentPostId = postId;
$('#vh360-post-edit-modal').addClass('show');
$.ajax({
url: vh360CreatePost.ajaxUrl,
type: 'POST',
data: {
action: 'vh360_get_post_data',
post_id: postId,
nonce: vh360CreatePost.nonce
},
success: function(response) {
if (response.success && response.data) {
var post = response.data;
$('#vh360-edit-post-id').val(postId);
$('#vh360-edit-post-title').val(post.title);
$('#vh360-edit-post-content').val(post.content);
$('#vh360-edit-post-excerpt').val(post.excerpt);
$('#vh360-edit-char-count').text(post.excerpt.length);
$('#vh360-edit-post-tags').val(post.tags);
$('#vh360-edit-post-status').val(post.status);
$('#vh360-edit-post-categories option').prop('selected', false);
if (post.categories && post.categories.length > 0) {
post.categories.forEach(function(catId) {
$('#vh360-edit-post-categories option[value="' + catId + '"]').prop('selected', true);
});
}
if (post.thumbnail_url) {
$('#vh360-edit-preview-img').attr('src', post.thumbnail_url);
$('#vh360-edit-image-preview').show();
$('#vh360-edit-featured-image-id').val(post.thumbnail_id || '0');
} else {
$('#vh360-edit-preview-img').attr('src', '');
$('#vh360-edit-image-preview').hide();
$('#vh360-edit-featured-image-id').val('0');
}
} else {
self.showNotification(response.data.message || 'Failed to load post data', 'error');
}
},
error: function() {
self.showNotification('An error occurred while loading post data', 'error');
}
});
},
updatePost: function() {
var self = this;
var $form = $('#vh360-post-edit-form');
var $btn = $form.find('button[type="submit"]');
$btn.prop('disabled', true).text('Updating...');
var fileInput = document.getElementById('vh360-edit-featured-image');
var featuredImageId = $('#vh360-edit-featured-image-id').val();
if (fileInput && fileInput.files && fileInput.files[0] && featuredImageId === '-1') {
self.uploadEditImage(fileInput.files[0], function(attachmentId) {
self.performPostUpdate(attachmentId, $btn);
}, function() {
$btn.prop('disabled', false).text('Update Post');
});
} else {
self.performPostUpdate(featuredImageId, $btn);
}
},
uploadEditImage: function(file, successCallback, errorCallback) {
var formData = new FormData();
formData.append('action', 'vh360_upload_image');
formData.append('nonce', vh360CreatePost.nonce);
formData.append('image', file);
$.ajax({
url: vh360CreatePost.ajaxUrl,
type: 'POST',
data: formData,
processData: false,
contentType: false,
success: function(response) {
if (response.success && response.data.attachment_id) {
successCallback(response.data.attachment_id);
} else {
this.showNotification(response.data.message || 'Failed to upload image', 'error');
errorCallback();
}
}.bind(this),
error: function() {
this.showNotification('An error occurred while uploading image', 'error');
errorCallback();
}.bind(this)
});
},
performPostUpdate: function(featuredImageId, $btn) {
var self = this;
$.ajax({
url: vh360CreatePost.ajaxUrl,
type: 'POST',
data: {
action: 'vh360_update_post',
post_id: $('#vh360-edit-post-id').val(),
title: $('#vh360-edit-post-title').val(),
content: $('#vh360-edit-post-content').val(),
excerpt: $('#vh360-edit-post-excerpt').val(),
categories: $('#vh360-edit-post-categories').val(),
tags: $('#vh360-edit-post-tags').val(),
status: $('#vh360-edit-post-status').val(),
featured_image_id: featuredImageId,
nonce: vh360CreatePost.nonce
},
success: function(response) {
if (response.success) {
self.showNotification(response.data.message || 'Post updated successfully', 'success');
self.closeModals();
setTimeout(function() {
location.reload();
}, 1000);
} else {
self.showNotification(response.data.message || 'Failed to update post', 'error');
}
},
error: function() {
self.showNotification('An error occurred', 'error');
},
complete: function() {
$btn.prop('disabled', false).text('Update Post');
}
});
},
confirmDelete: function(postId) {
this.currentPostId = postId;
$('#vh360-post-delete-modal').addClass('show');
},
deletePost: function() {
var self = this;
var $btn = $('#vh360-post-confirm-delete');
$btn.prop('disabled', true).text('Deleting...');
$.ajax({
url: vh360CreatePost.ajaxUrl,
type: 'POST',
data: {
action: 'vh360_delete_post',
post_id: self.currentPostId,
nonce: vh360CreatePost.nonce
},
success: function(response) {
if (response.success) {
self.showNotification(response.data.message || 'Post deleted successfully', 'success');
$('.vh360-post-delete').filter(function() {
return $(this).data('post-id') == self.currentPostId;
}).closest('.vh360-post-card').fadeOut(300, function() {
$(this).remove();
if ($('.vh360-post-card').length === 0) {
location.reload();
}
});
self.closeModals();
} else {
self.showNotification(response.data.message || 'Failed to delete post', 'error');
}
},
error: function() {
self.showNotification('An error occurred', 'error');
},
complete: function() {
$btn.prop('disabled', false).text('Delete Post');
}
});
},
closeModals: function() {
$('#vh360-post-edit-modal, #vh360-post-delete-modal').removeClass('show');
if ($('#vh360-post-edit-form').length) {
$('#vh360-post-edit-form')[0].reset();
}
},
showNotification: function(message, type) {
var $notification = $('<div class="vh360-notification vh360-notification-' + type + '"></div>').text(message);
$('body').append($notification);
setTimeout(function() {
$notification.addClass('show');
}, 10);
setTimeout(function() {
$notification.removeClass('show');
setTimeout(function() {
$notification.remove();
}, 300);
}, 3000);
},
isSubmitting: false,
currentPostId: null
};
$(document).ready(function() {
VH360CreatePost.init();
});
})(jQuery);
